head.script:
/**
 * 화 면 명 : 자산변경명세서
 * 메뉴경로 : 회계/재무회계/고정자산/
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/fi/fixedaset/fi_301_01_05b.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2025-12-30
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 *    5. footer에 값 처리
 * 참고사항 : 
 *    1. 그리드ID.setNoResultMessageVisible(false) 설정해줘야 그리드에 데이터없음 안보임
 *    2. "hiddenVisible":true 되어 있는 항목 일단 false 처리[hiddenCol="true" => hiddenCol="false"]
 * 수정이력 :
 *    - 2025-12-30      배기원    최초작성
 */
//hidden 값
scwin.txtCoClsCd    = "";      //회사구분코드(hidden, 회사팝업호출 시)

//로그인 정보
scwin.memJson;
scwin.vLoginCoCd;       //소속자회사
scwin.vLoginCoClsCd;    //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd;   //사용자소속구분코드
scwin.isSubCompany;
scwin.privAdmin;

scwin.initJson = {};    //초기세팅값(TOBE)
scwin.first = 0;

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    // scwin.f_SearchHeaderCreate();
    // //자산유형 조회
    // ds_asetPattern.DataId = "/ac.fi.fixedaset.RetreiveFixedAsetPatternListCMD.do?useYn=1";
    // ds_asetPattern.undoAll();
    // scwin.f_FieldClear();
    // scwin.f_setCompanyInfo();

    scwin.memJson = $c.data.getMemInfo();
    scwin.vLoginCoCd     = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                     //소속자회사
    scwin.vLoginCoClsCd  = $c.gus.cfIsNull(scwin.memJson["coClsCd"]) ? "" : scwin.memJson["coClsCd"];               //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson["userHomeClsCd"]) ? "" : scwin.memJson["userHomeClsCd"];   //사용자소속구분코드
    scwin.isSubCompany   = false;
    scwin.privAdmin      = $c.gus.cfIsNull(scwin.memJson["privAdmin"]) ? "" : scwin.memJson["privAdmin"];           //관리자권한
    scwin.first = 0;

    const codeOptions = [
        { grpCd: "FI014", compID: "lc_fixedAsetHistClsCd" }   //고정자산이력구분
    ];
    $c.data.setCommonCode(codeOptions, scwin.callBackCommonCode);
};

/**
 * $c.data.setCommonCode 함수의 콜백함수
 */
scwin.callBackCommonCode = function() {
    dlt_commonCodeFI014.sort("cd", 0);

    scwin.initJson = dma_search.getJSON();
};

/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    gr_master.setNoResultMessageVisible(false);
    ds_master.reform();
    ds_master.removeAll();
    totalRows.setValue("0");
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    scwin.f_asetPattern();
    scwin.setInit();
    scwin.f_SetSrchDefault();
    scwin.f_setCompanyInfo();
};

/**
 * 자산유형 조회
 */
scwin.f_asetPattern = function() {
    ds_asetPattern.removeAll();
    $c.sbm.execute(sbm_asetPattern, {"useYn":"1"});
    ds_asetPattern.sort("asetPatternCd", 0);
};


/**
 * 조회 기본값 설정
 */
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search, [ed_coCd, ed_coNm, ica_acqDtStDt, ica_acqDtEndDt]);
    //dma_search.setJSON(scwin.initJson);
    scwin.f_SetSrchDefault();
    ed_coCd.hidVal    = "";         //회사코드(조회)
    ed_srchAcctDeptCd.hidVal = "";  //귀속부서코드(조회)
};


/**
 * 자회사 회계 시스템 추가에 따른 설정 
 */
scwin.f_setCompanyInfo = function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를 '동부 EXPRESS'로 Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
};

/**
 * 조회 기본값 설정
 */
scwin.f_SetSrchDefault = function() {
    ed_srchFixedAsetNo.setValue("");
    lc_fixedAsetHistClsCd.setValue("");
    lc_asetPatternCd.setValue("");
    let today = $c.date.getServerDateTime();
    ica_acqDtStDt.setValue(today.substring(0,6) + "01");
    ica_acqDtEndDt.setValue(today);    
    ica_acqDtStDt.focus();
};


/**
 * 조회
 */
scwin.f_Retrieve = async function () {
    let ret = await scwin.f_Validation();
    if(!ret) {
        return;
    }

    scwin.setInit();
    dma_search.set("coClsCd", scwin.txtCoClsCd);
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_master.setNoResultMessageVisible(true);
    let rowCnt = ds_master.getRowCount();
    totalRows.setValue(rowCnt);

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        if (rowCnt == 0) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다

        } else {
            //조회된 결과 정렬(asis:<param name=SortExpr 참조)
            // ds_master.sort("seq", 0);
            gr_master.setFocusedCell(0, 0);
        }
    }
};

scwin.sbm_retrieve_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};


/**
 * 체크
 */
scwin.f_Validation = async function () {
    let ret;
    ret = await $c.gus.cfValidate([ed_coCd]);
    if(!ret) {
        return false;
    }

    ret = await $c.gus.cfValidate([ica_acqDtStDt, ica_acqDtEndDt, ed_srchAcctDeptCd]);
    if(!ret) {
        return false;
    }

    if ($c.gus.cfIsNull(ica_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ica_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ica_acqDtStDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ica_acqDtStDt.getValue()) && $c.gus.cfIsNull(ica_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ica_acqDtEndDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ica_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ica_acqDtEndDt.getValue())) {
        // if (!cfValidateValue(ica_acqDtEndDt.setValue, "minDate = " + ica_acqDtStDt.getValue())) {
        //     $c.win.alert(MSG_CM_ERR_039);
        //     ica_acqDtStDt.focus();
        //     return false;
        // }
        // 날짜체크
        if (!await $c.gus.cfIsAfterDate(ica_acqDtStDt.getValue().trim(), ica_acqDtEndDt.getValue().trim())) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            ica_acqDtEndDt.focus();
            return false;
        }
    }
    return true;
};

