/**
 * Object 값 반환함수
 * TOBE 사용안함
 */
scwin.f_GetObjValue = function (inObj) {
    return (inObj.tagName == "OBJECT") ? inObj.text : inObj.value;
};

/**
 * Object 값 설정함수
 * TOBE 사용안함
 */
scwin.f_SetObjValue = function (inObj, val) {
    if (inObj.tagName == "OBJECT")
        inObj.text = val;
    else
        inObj.value = val;
};

